import React, { useRef } from 'react';
import { Container, Typography, Box, Card, CardContent, Chip } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import BusinessIcon    from '@mui/icons-material/Business';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';
import SchoolIcon      from '@mui/icons-material/School';
import FitnessCenterIcon from '@mui/icons-material/FitnessCenter';
import AttachMoneyIcon from '@mui/icons-material/AttachMoney';
import PsychologyIcon  from '@mui/icons-material/Psychology';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import SmartToyIcon    from '@mui/icons-material/SmartToy';
import AssessmentIcon  from '@mui/icons-material/Assessment';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import { G } from '../theme';

/* 3D tilt card */
function TiltCard({ children, onClick, accentColor }) {
  const ref = useRef(null);
  const onMove = e => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const x = (e.clientX - r.left) / r.width  - 0.5;
    const y = (e.clientY - r.top)  / r.height - 0.5;
    ref.current.style.transform = `perspective(700px) rotateY(${x * 9}deg) rotateX(${-y * 9}deg) scale(1.04)`;
    ref.current.style.boxShadow = `${x * -14}px ${y * -14}px 32px rgba(26,61,43,0.16), 0 8px 32px rgba(26,61,43,0.10)`;
  };
  const onLeave = () => {
    if (!ref.current) return;
    ref.current.style.transform = 'perspective(700px) rotateY(0) rotateX(0) scale(1)';
    ref.current.style.boxShadow = '0 2px 16px rgba(26,61,43,0.07)';
  };
  return (
    <Card ref={ref} onClick={onClick} onMouseMove={onMove} onMouseLeave={onLeave}
      sx={{
        cursor: 'pointer',
        transition: 'transform 0.15s ease, box-shadow 0.15s ease',
        position: 'relative', overflow: 'hidden',
        '&::before': {
          content: '""', position: 'absolute', top: 0, left: 0, right: 0, height: 3,
          background: accentColor || G.btnGrad,
        }
      }}>
      {children}
    </Card>
  );
}

const sections = [
  { title: 'Business',   sub: 'Ideas & full blueprints',     icon: <BusinessIcon />,     path: '/business',  accent: G.pine,      bg: `rgba(45,106,79,0.09)`,  badge: 'Daily' },
  { title: 'Best Idea',  sub: 'Top 3 models to start now',   icon: <EmojiEventsIcon />,  path: '/best-idea', accent: G.fern,      bg: `rgba(58,125,92,0.09)`,  badge: '🔥 #1' },
  { title: 'Financial',  sub: 'Link card & track money',     icon: <AttachMoneyIcon />,  path: '/financial', accent: G.mid,       bg: `rgba(71,133,89,0.09)`,  badge: 'Smart' },
  { title: 'Mindset',    sub: 'Daily principles that stick', icon: <PsychologyIcon />,   path: '/mindset',   accent: G.moss,      bg: `rgba(82,148,106,0.09)`, badge: 'Daily' },
  { title: 'Learning',   sub: 'Read → quiz → level up',     icon: <SchoolIcon />,       path: '/learning',  accent: G.leaf,      bg: `rgba(98,168,120,0.09)`, badge: 'Quiz' },
  { title: 'Health',     sub: 'Workouts + meal plans',       icon: <FitnessCenterIcon />,path: '/health',    accent: G.sage,      bg: `rgba(122,184,147,0.09)`,badge: 'Today' },
  { title: 'Check-in',   sub: 'Daily 5-min reflection',      icon: <CheckCircleIcon />,  path: '/checkin',   accent: G.mint,      bg: `rgba(149,204,171,0.09)`,badge: '' },
  { title: 'Reports',    sub: 'Progress across all modules', icon: <AssessmentIcon />,   path: '/reports',   accent: G.mist,      bg: `rgba(180,221,197,0.09)`,badge: '' },
  { title: 'AI Advisor', sub: 'Personal AI strategist',      icon: <SmartToyIcon />,     path: '/ai',        accent: G.pine,      bg: `rgba(45,106,79,0.09)`,  badge: 'AI' },
];

export default function Dashboard() {
  const navigate = useNavigate();
  const hr = new Date().getHours();
  const greeting = hr < 12 ? 'Good Morning' : hr < 17 ? 'Good Afternoon' : 'Good Evening';
  const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

  return (
    <Container maxWidth="xl" sx={{ py: 2 }}>

      {/* ── Hero banner ─────────────────── */}
      <Box sx={{
        mb: 5, p: { xs: 3, sm: 5 }, borderRadius: 4,
        background: G.heroGrad,
        position: 'relative', overflow: 'hidden',
        boxShadow: '0 12px 40px rgba(26,61,43,0.30)',
      }}>
        {/* Decorative forest rings */}
        {[380, 280, 180].map((sz, i) => (
          <Box key={i} sx={{
            position: 'absolute', right: -sz * 0.3, top: '50%',
            width: sz, height: sz, borderRadius: '50%',
            border: `1px solid rgba(148,204,171,${0.08 + i * 0.04})`,
            transform: 'translateY(-50%)',
          }} />
        ))}
        {/* Leaf accent */}
        <Box sx={{
          position: 'absolute', top: -30, right: 60, fontSize: '7rem',
          opacity: 0.07, transform: 'rotate(25deg)', pointerEvents: 'none',
          userSelect: 'none', lineHeight: 1,
        }}>🌿</Box>

        <Box sx={{ position: 'relative', zIndex: 1 }}>
          <Typography variant="caption" sx={{
            color: 'rgba(232,245,238,0.45)', letterSpacing: 3,
            textTransform: 'uppercase', fontSize: '0.68rem'
          }}>
            {today}
          </Typography>
          <Typography variant="h3" fontWeight={900} sx={{
            color: G.foam, mt: 0.5, lineHeight: 1.15,
            fontSize: { xs: '1.8rem', sm: '2.4rem' }
          }}>
            {greeting}, <Box component="span" sx={{ color: G.mint }}>Sirawdink</Box> 👋
          </Typography>
          <Typography sx={{ color: 'rgba(232,245,238,0.58)', mt: 1.5, maxWidth: 480, lineHeight: 1.75 }}>
            Your personal operating system. Every tool you need to grow — all in one place.
          </Typography>
          <Box sx={{ display: 'flex', gap: 1, mt: 3, flexWrap: 'wrap' }}>
            {[
              { label: 'Business Ideas',    color: G.sage },
              { label: 'Finance Tracking',  color: G.mint },
              { label: 'AI Learning',       color: G.mist },
              { label: 'Daily Workouts',    color: G.pale },
            ].map(t => (
              <Chip key={t.label} label={`✓ ${t.label}`} size="small" sx={{
                bgcolor: 'rgba(232,245,238,0.1)', color: t.color,
                border: `1px solid rgba(232,245,238,0.18)`, fontWeight: 600,
              }} />
            ))}
          </Box>
        </Box>
      </Box>

      {/* ── Stats row ───────────────────── */}
      <Box sx={{
        display: 'grid', gap: 2, mb: 4,
        gridTemplateColumns: { xs: 'repeat(2,1fr)', sm: 'repeat(4,1fr)' }
      }}>
        {[
          { label: 'Business Ideas',  value: '4+',  top: G.pine  },
          { label: 'Courses Ready',   value: '3',   top: G.fern  },
          { label: 'Workout Plans',   value: '7',   top: G.mid   },
          { label: 'AI Responses',    value: '∞',   top: G.sage  },
        ].map(s => (
          <Card key={s.label} sx={{
            background: 'rgba(255,255,255,0.78)',
            backdropFilter: 'blur(12px)',
            overflow: 'hidden', position: 'relative',
            '&::before': { content: '""', position: 'absolute', top: 0, left: 0, right: 0, height: 3, background: s.top },
            transition: 'transform 0.2s', '&:hover': { transform: 'translateY(-3px)' }
          }}>
            <CardContent sx={{ p: 2.5, textAlign: 'center' }}>
              <Typography variant="h3" fontWeight={900} sx={{ color: s.top, lineHeight: 1 }}>{s.value}</Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: G.textMid }}>{s.label}</Typography>
            </CardContent>
          </Card>
        ))}
      </Box>

      {/* ── Module grid ─────────────────── */}
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2.5 }}>
        <Typography variant="overline" sx={{ color: G.textLight, letterSpacing: 3, fontWeight: 700 }}>
          Your Modules
        </Typography>
        <Typography variant="caption" sx={{ color: G.textLight }}>
          Hover to interact · Click to open
        </Typography>
      </Box>

      <Box sx={{
        display: 'grid', gap: 2,
        gridTemplateColumns: { xs: 'repeat(2,1fr)', sm: 'repeat(3,1fr)', xl: 'repeat(3,1fr)' }
      }}>
        {sections.map(s => (
          <TiltCard key={s.title} onClick={() => navigate(s.path)} accentColor={s.accent}>
            <CardContent sx={{ p: { xs: 2, sm: 3 } }}>
              <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', mb: 2.5 }}>
                <Box sx={{
                  width: 48, height: 48, borderRadius: 3,
                  bgcolor: s.bg, display: 'flex', alignItems: 'center', justifyContent: 'center',
                  color: s.accent,
                }}>
                  {s.icon}
                </Box>
                {s.badge && (
                  <Chip label={s.badge} size="small" sx={{
                    bgcolor: s.bg, color: s.accent, fontWeight: 700, fontSize: '0.65rem',
                    border: `1px solid ${s.accent}30`,
                  }} />
                )}
              </Box>
              <Typography fontWeight={700} sx={{ color: G.forest, fontSize: '0.95rem', mb: 0.3 }}>
                {s.title}
              </Typography>
              <Typography variant="caption" sx={{ color: G.textLight, lineHeight: 1.5, display: 'block', mb: 2 }}>
                {s.sub}
              </Typography>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, color: s.accent }}>
                <Typography variant="caption" fontWeight={700} sx={{ fontSize: '0.72rem', letterSpacing: 0.5 }}>
                  OPEN
                </Typography>
                <ArrowForwardIcon sx={{ fontSize: 13 }} />
              </Box>
            </CardContent>
          </TiltCard>
        ))}
      </Box>
    </Container>
  );
}
